#include <stdio.h>

int original(int a, int b) {
    int rem = a & 1;
    int rem1 = b & 1;
    int add = rem1 + rem;  // nuw nsw
    int div2 = (unsigned)add >> 1;
    return div2;
}

int current_opt(int a, int b) {
    int rem = a & 1;
    int div2 = rem & b;
    return div2;
}

int expected_opt(int a, int b) {
    int and_val = a & 1;
    int and1 = and_val & b;
    return and1;
}

int main() {
    int test_values[] = {0, 1, 2, 3, 4, 5, -1, -2};
    int num_tests = sizeof(test_values) / sizeof(test_values[0]);

    for (int i = 0; i < num_tests; i++) {
        for (int j = 0; j < num_tests; j++) {
            int a = test_values[i];
            int b = test_values[j];
            int orig = original(a, b);
            int curr = current_opt(a, b);
            int exp = expected_opt(a, b);

            if (orig != curr || orig != exp) {
                printf("MISMATCH: a=%d, b=%d\n", a, b);
                printf("  original = %d\n", orig);
                printf("  current  = %d\n", curr);
                printf("  expected = %d\n", exp);
            }
        }
    }
    printf("Test complete\n");
    return 0;
}
