#include <stdio.h>

// Original: ((X & 1) + (Y & 1)) >> 1
int original(int X, int Y) {
    return ((X & 1) + (Y & 1)) >> 1;
}

// Current opt: (X & 1) & Y
int current_opt(int X, int Y) {
    return (X & 1) & Y;
}

// Expected opt: (X & 1) & (Y & 1)
int expected_opt(int X, int Y) {
    return (X & 1) & (Y & 1);
}

int main() {
    int mismatches = 0;
    for (int i = -10; i <= 10; i++) {
        for (int j = -10; j <= 10; j++) {
            int o = original(i, j);
            int c = current_opt(i, j);
            int e = expected_opt(i, j);

            if (o != c) {
                printf("MISMATCH current: x=%d y=%d original=%d current=%d\n", i, j, o, c);
                mismatches++;
            }
            if (o != e) {
                printf("MISMATCH expected: x=%d y=%d original=%d expected=%d\n", i, j, o, e);
                mismatches++;
            }
        }
    }
    if (mismatches == 0) {
        printf("All tests passed! The transformations are equivalent.\n");
    } else {
        printf("Total mismatches: %d\n", mismatches);
    }
    return 0;
}
